def _load_embedder(spec: str) -> Any:
    """
    Load an object or factory from "module:attr".
    If it's a class: instantiate with no args. If it's a callable: call to get the object.
    Otherwise: return the object itself.
    The returned object must expose `.encode(list[str]) -> ndarray`.
    """
    if not spec or ":" not in spec:
        raise ValueError('Embedder spec must be "module:attr" (got %r)' % spec)
    mod_name, attr = spec.split(":", 1)
    mod = importlib.import_module(mod_name)
    obj = getattr(mod, attr)
    if inspect.isclass(obj):
        return obj()
    if callable(obj) and not hasattr(obj, "encode"):
        # factory
        return obj()
    return obj

def normalize_imports_used(meta: dict):
    """
    Normalize the 'imports_used' field into iterable tuples.

    Accepts:
      - dict: alias -> full_module
      - list: full_module strings
      - None/missing

    Args:
        meta (dict): Metadata dictionary.

    Returns:
        list[tuple[str|None, str]]: Normalized imports.

    Example:
        >>> normalize_imports_used({"imports_used": {"np": "numpy"}})
        [('np', 'numpy')]
    """
    imports = meta.get("imports_used")
    if not imports:
        return []
    if isinstance(imports, dict):
        out = []
        for alias, full in imports.items():
            if not full:
                continue
            try:
                out.append((alias, str(full)))
            except Exception:
                continue
        return out
    if isinstance(imports, list):
        out = []
        for full in imports:
            if not full:
                continue
            try:
                out.append((None, str(full)))
            except Exception:
                continue
        return out
    logger.debug("Unexpected imports_used shape: %r", type(imports))
    return []

def add_defines_edges(G, chunks):
    """
    Add 'defines' edges for relationships:
      - class -> method
      - class -> nested class
      - function/method -> lambda

    Note: doesn’t need to add anything for non-nested classes — they’re already connected at the file level.

    Args:
        G (nx.Graph): The graph.
        chunks (list): List of code chunks.

    Example:
        >>> G, indices = init_graph(), init_indices()
        >>> ch = {"id": "f.py::method::C.m", "file": "f.py", "type": "function"}
        >>> G.add_node("f.py::class::C", type="class")
        >>> add_defines_edges(G, [ch])
        >>> list(G.edges("f.py::class::C"))
        [('f.py::class::C', 'f.py::method::C.m')]
    """
    # class -> method
    for ch in chunks:
        try:
            if "::method::" in ch.get("id", ""):
                cfile = ch["file"]
                qual = ch["id"].split("::method::", 1)[1]
                class_name = qual.split(".", 1)[0]
                class_id = f"{cfile}::class::{class_name}"
                if class_id in G:
                    G.add_edge(class_id, ch["id"], type="defines")
        except Exception as e:
            logger.debug("Skipping class->method link: %s (%s)", ch, e)

    # class -> nested class
    for ch in chunks:
        try:
            if ch.get("type") == "class":
                enclosing_cls = meta_of(ch).get("enclosing_class") or ch.get("parent_class")
                if enclosing_cls:
                    parent_id = f"{ch['file']}::class::{enclosing_cls}"
                    if parent_id in G:
                        G.add_edge(parent_id, ch["id"], type="defines")
        except Exception as e:
            logger.debug("Skipping nested class link: %s (%s)", ch, e)

    # function/method -> lambda
    for ch in chunks:
        try:
            if ch.get("type") == "lambda":
                enc = meta_of(ch).get("enclosing") or ch.get("parent_function") or ch.get("parent_method")
                if enc and enc in G:
                    G.add_edge(enc, ch["id"], type="defines")
        except Exception as e:
            logger.debug("Skipping lambda link: %s (%s)", ch, e)

def _as_rank_map(lst: ListLike) -> Dict[Id, Rank]:
    """
    Convert a list into {id: rank} (1-based). Supports:
      - ["a","b","c"]
      - [{"id":"a","rank":2}, {"id":"b","rank":1}]
      - [{"chunk_id":"a","score":0.9}, ...]  -> ranks by descending score
    """
    if not lst:
        return {}

    # case 1: pure id sequence
    if isinstance(lst[0], str):
        return {item: i + 1 for i, item in enumerate(lst)}  # type: ignore[arg-type]

    # case 2/3: dicts
    if isinstance(lst[0], Mapping):
        first = lst[0]  # type: ignore[index]
        if "rank" in first:
            # explicit rank
            items = [(str(d.get("id") or d.get("chunk_id")), int(d["rank"])) for d in lst]  # type: ignore[index]
            # ensure smallest rank is best (1-based)
            return {i: r for i, r in items if i}
        elif "score" in first:
            # convert scores to ranks (higher score -> better rank)
            scored: List[Tuple[Id, Score]] = []
            for d in lst:  # type: ignore[index]
                cid = str(d.get("id") or d.get("chunk_id") or "")
                if not cid:
                    continue
                s = float(d.get("score", 0.0))
                scored.append((cid, s))
            scored.sort(key=lambda t: (-t[1], t[0]))
            return {cid: i + 1 for i, (cid, _) in enumerate(scored)}
        elif "id" in first or "chunk_id" in first:
            # implicit by order
            ids = [str(d.get("id") or d.get("chunk_id")) for d in lst]  # type: ignore[index]
            return {cid: i + 1 for i, cid in enumerate([x for x in ids if x])}

    # fallback
    logger.debug("rrf._as_rank_map: unrecognized list shape; treating as empty.")
    return {}

class LexicalIndex:
    def __init__(self) -> None:
        self.df: Dict[str, int] = {}                       # term -> doc freq
        self.postings: Dict[str, Dict[str, _Posting]] = {} # term -> {chunk_id -> posting}
        self.doc_len: Dict[str, int] = {}                  # chunk_id -> length in tokens
        self.N: int = 0
        self.avgdl: float = 0.0

        # params (BM25-ish)
        self.k1: float = 1.2
        self.b: float = 0.75

    # ---------- build ----------

    @classmethod
    def from_records(cls, records: List[Dict]) -> "LexicalIndex":
        self = cls()

        for rec in records:
            cid = rec.get("id")
            if not isinstance(cid, str) or not cid:
                continue
            lex = rec.get("lexical_helpers") or {}
            toks: List[str] = []
            toks.extend(lex.get("ngrams_1") or [])
            # light boost to bigrams by duplicating once (stable & deterministic)
            bigrams = lex.get("ngrams_2") or []
            toks.extend(bigrams)
            toks.extend(bigrams)  # duplicate to act as a 2x weight

            dl = 0
            seen_in_doc = set()
            for t in toks:
                if not t:
                    continue
                dl += 1
                self.postings.setdefault(t, {}).setdefault(cid, _Posting(tf=0)).tf += 1
                if t not in seen_in_doc:
                    self.df[t] = self.df.get(t, 0) + 1
                    seen_in_doc.add(t)

            self.doc_len[cid] = dl
            self.N += 1

        self.avgdl = (sum(self.doc_len.values()) / self.N) if self.N else 0.0
        return self

    # ---------- scoring ----------

    def _idf(self, term: str) -> float:
        # BM25 idf variant; add-1 smoothing for determinism
        n = self.df.get(term, 0)
        if n <= 0 or self.N == 0:
            return 0.0
        return math.log(1 + (self.N - n + 0.5) / (n + 0.5))

    def _score_doc(self, cid: str, q_terms: List[str]) -> float:
        dl = max(1, self.doc_len.get(cid, 1))
        K = self.k1 * ((1 - self.b) + self.b * (dl / (self.avgdl or 1.0)))
        score = 0.0
        for t in q_terms:
            p = self.postings.get(t, {}).get(cid)
            if not p:
                continue
            idf = self._idf(t)
            tf = p.tf
            score += idf * ((tf * (self.k1 + 1)) / (tf + K))
        return score

    # ---------- query ----------

    def search(self, query: str, *, top_k: int = 50) -> List[Dict]:
        q_terms = _tokenize_lc(query)
        # gather candidate set from union of postings
        cands = set()
        for t in q_terms:
            if t in self.postings:
                cands.update(self.postings[t].keys())

        scored: List[Tuple[str, float]] = []
        for cid in cands:
            s = self._score_doc(cid, q_terms)
            if s > 0.0:
                scored.append((cid, s))

        scored.sort(key=lambda kv: (-kv[1], kv[0]))
        out: List[Dict] = []
        for i, (cid, s) in enumerate(scored[:top_k], start=1):
            out.append({"chunk_id": cid, "score": float(s), "rank": i})
        return out

def _idf(self, term: str) -> float:
