def _to_faiss_ids(rows: List[Dict[str, Any]]) -> np.ndarray:
    """Return a dense 0..N-1 int64 id array for FAISS; keep original ids in meta/rows."""
    return np.arange(len(rows), dtype=np.int64)

def save_jsonl(items: List[Dict[str, Any]], path: str) -> None:
    _ensure_dir(os.path.dirname(path) or ".")
    with open(path, "w", encoding="utf-8") as f:
        for it in items:
            if not isinstance(it, dict):
                logger.warning("save_jsonl: skipping non-dict item %r", it)
                continue
            f.write(json.dumps(it, ensure_ascii=False) + "\n")

def load_jsonl(path: str) -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            if not line.strip():
                continue
            try:
                obj = json.loads(line)
                if isinstance(obj, dict):
                    out.append(obj)
                else:
                    logger.warning("load_jsonl: skipping non-dict object %r", obj)
            except Exception as e:
                logger.error("load_jsonl: failed to parse line %r (%s)", line.strip(), e)
    return out

def save_indices(indices: Dict[str, Any], out_dir: str) -> None:
    """
    Save per-view FAISS indices (if present) and metadata/rows.
    Layout:
      out_dir/
        meta.json
        intent.index, intent.rows.jsonl
        impl.index,   impl.rows.jsonl
    """
    _ensure_dir(out_dir)

    meta = {
        "metric": indices.get("metric"),
        "views": {},
    }

    for view in ("intent", "impl"):
        v = indices.get("views", {}).get(view) or {}
        rows = v.get("rows") or []
        idx = v.get("index")
        vdir = out_dir
        # rows
        save_jsonl(rows, os.path.join(vdir, f"{view}.rows.jsonl"))
        # index
        if idx is not None and _FAISS:
            try:
                faiss.write_index(idx, os.path.join(vdir, f"{view}.index"))  # type: ignore
                meta["views"][view] = {"has_index": True}
            except Exception as e:
                logger.warning("Failed to save FAISS index for view %s: %s", view, e)
                meta["views"][view] = {"has_index": False}
        else:
            meta["views"][view] = {"has_index": False}

    with open(os.path.join(out_dir, "meta.json"), "w", encoding="utf-8") as f:
        json.dump(meta, f, ensure_ascii=False, indent=2)

def load_indices(in_dir: str) -> Dict[str, Any]:
    """
    Load indices and rows from a directory created by save_indices.
    Will set index=None if FAISS is unavailable or the file is missing.
    """
    with open(os.path.join(in_dir, "meta.json"), "r", encoding="utf-8") as f:
        meta = json.load(f)

    result = {"metric": meta.get("metric"), "views": {}}
    for view in ("intent", "impl"):
        rows = load_jsonl(os.path.join(in_dir, f"{view}.rows.jsonl"))
        index_path = os.path.join(in_dir, f"{view}.index")
        idx = None
        if _FAISS and os.path.exists(index_path):
            try:
                idx = faiss.read_index(index_path)  # type: ignore
            except Exception as e:
                logger.warning("Failed to load FAISS index for %s: %s", view, e)
        result["views"][view] = {"index": idx, "rows": rows, "ids": None, "meta": None}
    return result

def load_graph_json(path: str):
    if not _NX:
        raise RuntimeError("networkx is required to save/load graphs.")
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
    return json_graph.node_link_graph(data)

def _attribute_roots_read(meta: Dict[str, Any]) -> List[str]:
    """
    Extract root attributes accessed via `self.<attr>` from metadata.

    Args:
        meta (Dict[str, Any]): Metadata dictionary.

    Returns:
        List[str]: Sorted unique root attributes.
    """
    roots = set()
    try:
        reads = meta.get("attributes_used") or meta.get("reads") or []
        for dotted in reads if isinstance(reads, list) else []:
            if isinstance(dotted, str) and dotted.startswith("self."):
                after = dotted.split("self.", 1)[1]
                root = after.split(".", 1)[0]
                if root:
                    roots.add(root)
    except Exception:
        pass
    return sorted(roots)

def _normalize_raises(meta: Dict[str, Any]) -> List[str]:
    """
    Normalize exceptions raised into a consistent list of names.

    Args:
        meta (Dict[str, Any]): Metadata containing "raises".

    Returns:
        List[str]: Sorted list of exception names.
    """
    out: List[str] = []
    rs = meta.get("raises") or []
    if isinstance(rs, list):
        for r in rs:
            if isinstance(r, str) and r:
                out.append(r)
            elif isinstance(r, dict):
                nm = r.get("name")
                if nm:
                    out.append(str(nm))
    return sorted(set(out))

def _imports_full(meta: Dict[str, Any]) -> List[str]:
    """
    Collect full import paths from metadata.

    Args:
        meta (Dict[str, Any]): Metadata containing "imports_used".

    Returns:
        List[str]: Sorted list of fully qualified imports.
    """
    fulls = set()
    imps = meta.get("imports_used")
    if isinstance(imps, dict):
        for full in imps.values():
            if isinstance(full, str) and full:
                fulls.add(full)
    elif isinstance(imps, list):
        for full in imps:
            if isinstance(full, str) and full:
                fulls.add(full)
    return sorted(fulls)

def _calls_out_ids(G, node_id: str) -> Tuple[List[str], List[str]]:
    """
    Collect outgoing call targets from a node.

    Args:
        G: Graph object (networkx).
        node_id (str): Node identifier.

    Returns:
        Tuple[List[str], List[str]]: 
            - internal_targets: ids of project functions/methods/lambdas.
            - unresolved_names: unresolved function names.
    """
    internal: List[str] = []
    unresolved: List[str] = []
    try:
        if G is None or node_id not in G:
            return internal, unresolved
        for succ in G.successors(node_id):
            ed = G[node_id][succ]
            attrs = ed if isinstance(ed, dict) and not any(isinstance(v, dict) for v in ed.values()) \
                    else (list(ed.values())[0] if isinstance(ed, dict) and ed else {})
            if attrs.get("type") == "calls":
                st = G.nodes[succ].get("type")
                if attrs.get("internal") is True and st in {"function", "method", "lambda"}:
                    internal.append(succ)
                elif st == "unresolved":
                    name = G.nodes[succ].get("name")
                    if isinstance(name, str) and name:
                        unresolved.append(name)
        return sorted(set(internal)), sorted(set(unresolved))
    except Exception:
        return internal, unresolved

def _calls_degree(G, node_id: str) -> Tuple[int, int]:
    """
    Count number of incoming and outgoing call edges.

    Args:
        G: Graph object (networkx).
        node_id (str): Node identifier.

    Returns:
        Tuple[int, int]: (calls_in_count, calls_out_count)
    """
    cin = cout = 0
    try:
        if G is None or node_id not in G:
            return 0, 0
        for pred in G.predecessors(node_id):
            ed = G[pred][node_id]
            attrs = ed if isinstance(ed, dict) and not any(isinstance(v, dict) for v in ed.values()) \
                    else (list(ed.values())[0] if isinstance(ed, dict) and ed else {})
            if attrs.get("type") == "calls":
                cin += 1
        for succ in G.successors(node_id):
            ed = G[node_id][succ]
            attrs = ed if isinstance(ed, dict) and not any(isinstance(v, dict) for v in ed.values()) \
                    else (list(ed.values())[0] if isinstance(ed, dict) and ed else {})
            if attrs.get("type") == "calls":
                cout += 1
        return int(cin), int(cout)
    except Exception:
        return 0, 0

def _doc_first_sentence(meta: Dict[str, Any]) -> str:
    """
    Use parsed docstring summary when available, else fallback to first line of raw docstring.
    """
    try:
        parsed = meta.get("doc_parsed") or {}
        summ = parsed.get("summary")
        if isinstance(summ, str) and summ.strip():
            return summ.strip()
    except Exception:
        pass
    raw = meta.get("docstring") or ""
    return _first_sentence(raw)

def _attribute_roots_read(meta: Dict[str, Any]) -> List[str]:
    """
    Unique roots for `self.foo.*` -> 'foo'. Sorted for determinism.
    """
    roots = set()
    try:
        reads = meta.get("attributes_used") or meta.get("reads") or []
        for dotted in reads if isinstance(reads, list) else []:
            if isinstance(dotted, str) and dotted.startswith("self."):
                try:
                    after = dotted.split("self.", 1)[1]
                    root = after.split(".", 1)[0]
                    if root:
                        roots.add(root)
                except Exception:
                    continue
    except Exception:
        pass
    return sorted(roots)

def _attribute_roots_written(meta: Dict[str, Any]) -> List[str]:
    """
    Unique instance attribute roots written (from instance_attributes).
    """
    roots = set()
    try:
        writes = meta.get("instance_attributes") or []
        if isinstance(writes, list):
            for it in writes:
                if isinstance(it, dict):
                    nm = it.get("name")
                    if nm:
                        roots.add(str(nm))
    except Exception:
        pass
    # Fallback: some pipelines might carry a plain list in 'writes'
    if not roots:
        try:
            writes2 = meta.get("writes") or []
            for w in writes2 if isinstance(writes2, list) else []:
                if isinstance(w, str) and w:
                    roots.add(w)
        except Exception:
            pass
    return sorted(roots)

def _imports_fullnames(meta: Dict[str, Any]) -> List[str]:
    """
    Return sorted list of full import module names (deduped).
    Accepts meta['imports_used'] as dict alias->full or list of full strings.
    """
    fulls = set()
    imps = meta.get("imports_used")
    if isinstance(imps, dict):
        for full in imps.values():
            if isinstance(full, str) and full:
                fulls.add(full)
    elif isinstance(imps, list):
        for full in imps:
            if isinstance(full, str) and full:
                fulls.add(full)
    return sorted(fulls)

def _raises_list(meta: Dict[str, Any]) -> List[str]:
    """
    Normalize raises to list[str].
    """
    out: List[str] = []
    rs = meta.get("raises") or []
    if isinstance(rs, list):
        for r in rs:
            if isinstance(r, str) and r:
                out.append(r)
            elif isinstance(r, dict):
                nm = r.get("name")
                if nm:
                    out.append(str(nm))
    return sorted(set(out))

def _topk_callee_names(meta: Dict[str, Any], k: int = 10) -> List[str]:
    """
    Deterministic top-K callee names by frequency, then alphabetical as tie-breaker.
    """
    freq: Dict[str, int] = {}
    calls = meta.get("calls_detailed") or []
    if isinstance(calls, list):
        for c in calls:
            if isinstance(c, dict):
                nm = c.get("callee_name")
                if isinstance(nm, str) and nm:
                    freq[nm] = freq.get(nm, 0) + 1
    items = sorted(freq.items(), key=lambda kv: (-kv[1], kv[0]))
    return [nm for nm, _ in items[:k]]

def _called_by_count(node_id: str, G) -> int:
    """
    Count inbound call edges to this node. If G is a MultiDiGraph, we count edges of type='calls'.
    If G is None or the node doesn't exist, returns 0.
    """
    try:
        if G is None or node_id not in G:
            return 0
        # Support DiGraph or MultiDiGraph with aggregated attributes
        cnt = 0
        # Prefer predecessor iteration for clarity
        for u in G.predecessors(node_id):
            edata = G[u][node_id]
            # MultiDiGraph => dict of dicts; DiGraph => single dict
            if isinstance(edata, dict) and any(isinstance(v, dict) for v in edata.values()):
                # MultiDiGraph path
                for ed in edata.values():
                    if ed.get("type") == "calls":
                        cnt += 1
            else:
                if edata.get("type") == "calls":
                    cnt += 1
        return int(cnt)
    except Exception:
        return 0

def _metrics_meta(meta: Dict[str, Any]) -> Tuple[Optional[int], Optional[int], bool, bool]:
    """
    Pick standard metrics for the card: n_loc, n_params, async, generator.
    """
    try:
        m = meta.get("metrics") or {}
        n_loc = m.get("n_loc")
        n_params = m.get("n_params")
        is_async = bool(meta.get("is_async", False))
        is_gen = bool(meta.get("is_generator", False))
        return n_loc, n_params, is_async, is_gen
    except Exception:
        return None, None, False, False

def build_intent_view(chunk: Dict[str, Any], G=None, *, topk_callees: int = 10) -> str:
    """
    Build the NL-friendly "card" per your template, deterministically.

    Template:
        type: {type}
        symbol: {id}
        name: {name}
        file: {file}
        class: {class_name}
        signature: {signature}
        summary: {first_sentence_of_docstring_or_empty}

        imports: {comma_join(imports_used_fullnames_sorted)}
        reads: {comma_join(attribute_roots_read)}
        writes: {comma_join(attribute_roots_written)}
        raises: {comma_join(raises)}
        calls_out: {comma_join(topK_callee_names)}
        called_by_count: {n_incoming_calls}
        metrics: n_loc={n_loc}, n_params={n_params}, async={is_async}, generator={is_generator}

    For type in {"file","class"}, signature/class lines are omitted (empty).
    `called_by_count` uses the graph if provided; otherwise 0.
    """
    try:
        ctype = chunk.get("type", "")
        cid = chunk.get("id", "")
        name = chunk.get("name", "")
        file = chunk.get("file", "")
        meta = chunk.get("meta") or {}

        class_name = ""
        signature = ""
        if ctype in {"method", "function"}:
            class_name = (meta.get("class_name") or "") if ctype == "method" else ""
            signature = meta.get("signature") or ""

        summary = _doc_first_sentence(meta)
        imports = _imports_fullnames(meta)
        reads = _attribute_roots_read(meta)
        writes = _attribute_roots_written(meta)
        raises = _raises_list(meta)
        calls_out = _topk_callee_names(meta, k=topk_callees)
        n_called_by = _called_by_count(cid, G)
        n_loc, n_params, is_async, is_gen = _metrics_meta(meta)

        lines: List[str] = []
        lines.append(f"type: {ctype}")
        lines.append(f"symbol: {cid}")
        lines.append(f"name: {name}")
        lines.append(f"file: {file}")
        if ctype == "method":
            lines.append(f"class: {class_name}")
        else:
            lines.append("class: ")
        if ctype in {"function", "method"}:
            lines.append(f"signature: {signature}")
        else:
            lines.append("signature: ")
        lines.append(f"summary: {summary}")

        # deterministic comma joins
        def cj(xs: Iterable[str]) -> str:
            try:
                return ", ".join([x for x in xs if isinstance(x, str) and x])
            except Exception:
                return ""

        lines.append(f"imports: {cj(imports)}")
        lines.append(f"reads: {cj(reads)}")
        lines.append(f"writes: {cj(writes)}")
        lines.append(f"raises: {cj(raises)}")
        lines.append(f"calls_out: {cj(calls_out)}")
        lines.append(f"called_by_count: {n_called_by}")
        lines.append(
            "metrics: "
            f"n_loc={str(n_loc) if n_loc is not None else ''}, "
            f"n_params={str(n_params) if n_params is not None else ''}, "
            f"async={str(is_async)}, generator={str(is_gen)}"
        )
        return "\n".join(lines)
    except Exception as e:
        logger.error("build_intent_view failed for chunk %r: %s", chunk.get("id"), e)
        # Return a minimal, safe card
        return f"type: {chunk.get('type','')}\nsymbol: {chunk.get('id','')}\nname: {chunk.get('name','')}\nfile: {chunk.get('file','')}"

