def _visualize(node: str, rel_types: Optional[Iterable[str]], node_filter: Optional[Sequence[Tuple[str, str, Any]]] = None) -> None:
        try:
            edge_where = []
            if internal_only: edge_where.append(("internal", "==", True))
            if external_only: edge_where.append(("internal", "==", False))
            visualize_subgraph(
                Gq,
                center_node=node,
                depth=depth,
                relation_types=rel_types,
                node_where=node_filter,
                edge_where=edge_where if edge_where else None,
                edge_label_key="label_compact",
                width_by="call_sites_count",
            )
        except Exception as e:
            print(f"query_graph: visualization failed ({e}).")

def find_nodes_by_name(G, name, type_in=None, class_name=None, regex=False):
    """
    Find node IDs in the graph by name only.

    Args:
        G: networkx DiGraph
        name: str, the name to match (e.g. "load_config", "__init__", "SqlDB")
        type_in: optional set of node types to filter (e.g. {"function","method","class"})
        class_name: optional class name if you're looking for a method
        regex: if True, `name` is treated as a regex pattern

    Returns:
        list of matching node IDs
    """
    matches = []
    for nid, data in G.nodes(data=True):
        ntype = data.get("type")
        nname = data.get("name")

        if type_in and ntype not in type_in:
            continue

        if regex:
            import re
            if not re.search(name, str(nname)):
                continue
        else:
            if nname != name:
                continue

        if class_name:
            # For methods, check class context
            if data.get("class_name") == class_name:
                matches.append(nid)
                continue
            # Or parse it out of the ID suffix (::method::<Class>.<func>)
            if "::method::" in nid:
                qual = nid.split("::method::",1)[1]
                if qual.split(".",1)[0] == class_name:
                    matches.append(nid)
                continue
        else:
            matches.append(nid)

    return matches

def project_callees(G: nx.DiGraph, node_id: str):
    """
    Return IDs of in-project callees (functions/methods/lambdas) for the given node.
    """
    out, seen = [], set()
    for _, v, ed in G.out_edges(node_id, data=True):
        if ed.get("type") == "calls" and ed.get("internal") is True:
            t = G.nodes[v].get("type")
            if t in {"function", "method", "lambda"} and v not in seen:
                seen.add(v)
                out.append(v)
    return out

def _collect_top_level_members(tree: ast.AST, source: str) -> Dict[str, List[Dict[str, Any]]]:
        """
        Collect deterministic summaries of top-level members of a file, plus
        imports and globals. This ensures file-level meta is informative even if
        there is no module docstring.

        Returns:
            {
            "functions": [{"name": str, "signature": str, "docstring": str|None}],
            "classes":   [{"name": str, "signature": str, "docstring": str|None}],
            "imports":   [str],
            "globals":   [{"name": str, "value": str|None, "annotation": str|None}]
            }
        """
        out = {"functions": [], "classes": [], "imports": [], "globals": []}
        try:
            for n in getattr(tree, "body", []):
                if isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    out["functions"].append({
                        "name": n.name,
                        "signature": _signature_str(n.args),
                        "docstring": ast.get_docstring(n)
                    })
                elif isinstance(n, ast.ClassDef):
                    out["classes"].append({
                        "name": n.name,
                        "signature": _class_signature(n),
                        "docstring": ast.get_docstring(n)
                    })
                elif isinstance(n, (ast.Import, ast.ImportFrom)):
                    src = _get_source(source, n)
                    if src:
                        out["imports"].append(src.strip())
                elif isinstance(n, ast.Assign) and all(isinstance(t, ast.Name) for t in n.targets):
                    out["globals"].append({
                        "name": n.targets[0].id,
                        "value": _value_preview(n.value),
                        "annotation": None
                    })
                elif isinstance(n, ast.AnnAssign) and isinstance(n.target, ast.Name):
                    out["globals"].append({
                        "name": n.target.id,
                        "value": _value_preview(n.value),
                        "annotation": _unparse(n.annotation)
                    })
        except Exception:
            # Be defensive; partial is fine
            pass
        return out

