def visit_ClassDef(self, node: ast.ClassDef):
            """
            Visit a class definition and emit a class chunk.

            - Captures class decorators, bases, keywords, docstring.
            - Marks dataclass fields if decorated with @dataclass.
            - Tracks enclosing class context for nested classes.
            - Visits all methods and nested classes recursively.
            """
            class_id = f"{self.filename}::class::{node.name}"
            # Get source code segment of the source that generated node.
            class_code = _get_source(self.source, node) 
            # unparse an AST node decorator_list into its string representations.
            decorators = [_unparse(d) for d in node.decorator_list]

            # Capture enclosing class deterministically (for nested classes)
            enclosing = self.current_class_name

            meta: Dict[str, Any] = {
                "decorators": decorators,
                "bases": [_unparse(b) for b in node.bases],
                "keywords": {(kw.arg or ""): _unparse(kw.value) for kw in getattr(node, "keywords", [])}
                if getattr(node, "keywords", None)
                else {},
                "docstring": ast.get_docstring(node),
                "doc_parsed": _parse_docstring(ast.get_docstring(node)), #Parse a Python docstring into structured sections.
                "is_dataclass": any("dataclass" in (d or "") for d in decorators),
                "dataclass_fields": [],  # filled if dataclass with AnnAssigns
                "enclosing_class": enclosing,  # ★ NEW
            }
            if meta["is_dataclass"]:
                for stmt in node.body:
                    if isinstance(stmt, ast.AnnAssign) and isinstance(stmt.target, ast.Name):
                        meta["dataclass_fields"].append(
                            {
                                "name": stmt.target.id,
                                "annotation": _unparse(stmt.annotation),
                                "default": _value_preview(stmt.value),
                            }
                        )

            idx = len(code_chunks)
            code_chunks.append(
                {
                    "id": class_id,
                    "type": "class",
                    "name": node.name,
                    "file": self.filename,
                    "module_path": self.module_path,  # ★ NEW
                    "code": class_code,
                    "meta": meta,
                }
            )

            prev_class = self.current_class_name
            self.current_class_name = node.name

            # methods & nested
            for child in node.body:
                if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    self._visit_function_like(child, is_method=True)
                elif isinstance(child, ast.ClassDef):
                    # Nested class
                    self.visit(child)
                else:
                    self.visit(child)

            self.current_class_name = prev_class

def _detect_method_kind(self, decorators: List[str]) -> str:
            """
            Infer whether a function inside a class is a property,
            staticmethod, classmethod, or instance method.
            """
            if any(d.endswith(".setter") or d.endswith(".deleter") for d in decorators):
                return "property_accessor"
            if any(d.endswith(".getter") or d == "property" for d in decorators):
                return "property"
            if any(d.endswith("staticmethod") or d == "staticmethod" for d in decorators):
                return "staticmethod"
            if any(d.endswith("classmethod") or d == "classmethod" for d in decorators):
                return "classmethod"
            return "instance"

def visit_Assign(self, node: ast.Assign):
            """
            Visit assignment statements.
            - Distinguishes between instance attributes, locals, and tuple/list targets.
            """
            for tgt in node.targets:
                if isinstance(tgt, ast.Attribute) and isinstance(tgt.value, ast.Name) and tgt.value.id == "self":
                    src = None
                    if isinstance(node.value, ast.Name):
                        src = f"param: {node.value.id}"
                    self._record_instance_attr(
                        tgt.attr, None, node.value, getattr(node, "lineno", 0), source=src
                    )
                elif isinstance(tgt, ast.Name):
                    self._record_local(
                        tgt.id, None, node.value, getattr(node, "type_comment", None), getattr(node, "lineno", 0)
                    )
                elif isinstance(tgt, (ast.Tuple, ast.List)):
                    for elt in tgt.elts:
                        if isinstance(elt, ast.Name):
                            self._record_local(
                                elt.id, None, None, getattr(node, "type_comment", None), getattr(node, "lineno", 0)
                            )
            self.generic_visit(node)

def visit_AnnAssign(self, node: ast.AnnAssign):
            """
            Visit annotated assignment statements.
            - Records instance attributes or locals with type annotations.
            """
            ann = _unparse(node.annotation)
            if isinstance(node.target, ast.Attribute) and isinstance(node.target.value, ast.Name) and node.target.value.id == "self":
                self._record_instance_attr(node.target.attr, ann, node.value, getattr(node, "lineno", 0))
            elif isinstance(node.target, ast.Name):
                self._record_local(
                    node.target.id, ann, node.value, getattr(node, "type_comment", None), getattr(node, "lineno", 0)
                )
            self.generic_visit(node)

def visit_Attribute(self, node: ast.Attribute):
            """
            Record attribute usage inside current function.
            """
            if self.current_func_id and self.current_func_id in self.func_meta:
                dotted = _dotted_attr(node)
                if dotted:
                    self.func_meta[self.current_func_id]["attributes_used"].add(dotted)
            self.generic_visit(node)

def visit_Call(self, node: ast.Call):
            """
            Visit function/method calls.

            - Records call site details (callee, args, kwargs, lineno).
            - Adds call relation entry to global `call_relations`.
            - Updates function metadata (`calls_detailed`, metrics).
            """
            if self.current_func_id and self.current_func_id in self.func_meta:
                callee_full = _dotted_attr(node.func) or None
                if isinstance(node.func, ast.Name):
                    callee_name = node.func.id
                elif isinstance(node.func, ast.Attribute):
                    callee_name = node.func.attr
                elif callee_full:
                    callee_name = callee_full.split(".")[-1]
                else:
                    callee_name = None

                has_starargs = any(isinstance(a, ast.Starred) for a in node.args)
                has_kwargs = any(kw.arg is None for kw in node.keywords)

                self.func_meta[self.current_func_id]["calls_detailed"].append(
                    {
                        "callee_fullname": callee_full,
                        "callee_name": callee_name,
                        "args": [_unparse(a) for a in node.args],
                        "keywords": {(kw.arg if kw.arg is not None else "**"): _unparse(kw.value) for kw in node.keywords},
                        "has_starargs": has_starargs,
                        "has_kwargs": has_kwargs,
                        "lineno": getattr(node, "lineno", None),
                    }
                )

                if callee_name:
                    call_relations.append(
                        {
                            "caller_id": self.current_func_id,
                            "callee_name": callee_name,
                            "callee_fullname": callee_full,
                            "lineno": getattr(node, "lineno", None),
                        }
                    )
            self.generic_visit(node)

def _chunk_map(indices: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    """Build a map: chunk_id -> row (prefer intent view text)."""
    cmap: Dict[str, Dict[str, Any]] = {}
    views = indices.get("views") or {}
    for name in ["intent", "impl"]:
        vw = views.get(name) or {}
        for r in (vw.get("rows") or []):
            cid = r.get("chunk_id")
            if cid:
                cmap[str(cid)] = r
    return cmap

def _read_readme(project_root: Optional[str]) -> Optional[str]:
    if not project_root:
        return None
    for nm in ["README.md", "Readme.md", "readme.md"]:
        p = Path(project_root) / nm
        if p.exists():
            try:
                return p.read_text(encoding="utf-8", errors="ignore")
            except Exception:
                pass
    return None

def _guess_root(indices: Dict[str, Any]) -> Optional[str]:
    paths: List[str] = []
    for vw in (indices.get("views") or {}).values():
        for r in (vw.get("rows") or [])[:200]:
            p, _, _ = _split_chunk_id(r.get("chunk_id", ""))
            if p and os.path.isabs(p):
                paths.append(p)
    if not paths:
        return None
    try:
        return os.path.commonpath(paths)
    except Exception:
        return str(Path(paths[0]).parent)

def _trim(txt: Optional[str], max_chars: int) -> str:
    if txt is None:
        return ""
    t = str(txt)
    if len(t) <= max_chars:
        return t
    return t[: max_chars - 3] + "..."

def _as_sources_with_meta(
    hits: List[Dict[str, Any]],
    cmap: Dict[str, Dict[str, Any]],
    max_chunks: int = 24,
    max_chars: int = 900
) -> List[Dict[str, Any]]:
    """Select top hits and attach trimmed text + hit provenance for grounding & debug."""
    out: List[Dict[str, Any]] = []
    for h in hits[:max_chunks]:
        cid = str(h.get("chunk_id"))
        row = cmap.get(cid) or {}
        text = row.get("text", "") if isinstance(row, dict) else ""
        path, kind, symbol = _split_chunk_id(cid)
        prov = {}
        for k, v in (h or {}).items():
            if k == "chunk_id":
                continue
            if k == "provenance" and isinstance(v, dict):
                prov.update(v)
            else:
                prov[k] = v
        out.append({
            "chunk_id": cid,
            "path": path,
            "kind": kind,
            "symbol": symbol,
            "text": _trim(text, max_chars),
            "hit_meta": prov,
        })
    return out

def _symbol_tokens(question: str) -> List[str]:
    quoted = re.findall(r"[`\"]([A-Za-z_][A-Za-z0-9_]*)[`\"]", question or "")
    bare = re.findall(r"[A-Za-z_][A-Za-z0-9_]{2,}", question or "")
    seen, out = set(), []
    for t in quoted + bare:
        if t not in seen:
            seen.add(t); out.append(t)
    return out

def _find_symbol_rows(indices: Dict[str, Any], symbol: str) -> List[Tuple[str, Dict[str, Any], str]]:
    """Return list of (chunk_id, row, view) that match the symbol by cid/name/text."""
    out: List[Tuple[str, Dict[str, Any], str]] = []
    sym_l = symbol.lower()
    pat_def = re.compile(rf"\b(def|class)\s+{re.escape(symbol)}\b")
    for view in ["intent", "impl"]:
        vw = (indices.get("views") or {}).get(view) or {}
        for r in (vw.get("rows") or []):
            cid = str(r.get("chunk_id", ""))
            name = str(r.get("name", "")).lower()
            text = r.get("text", "") or ""
            if (
                f"::{symbol}" in cid or f"::{sym_l}" in cid.lower()
                or name == sym_l
                or pat_def.search(text) is not None
            ):
                out.append((cid, r, view))
    seen, dedup = set(), []
    for cid, r, view in out:
        if cid not in seen:
            seen.add(cid); dedup.append((cid, r, view))
    return dedup

def _hits_from_records(indices: Dict[str, Any], records_path: Optional[str], symbol: Optional[str]) -> List[Dict[str, Any]]:
    if not records_path or not symbol:
        return []
    try:
        recs = load_jsonl(records_path)
    except Exception:
        return []
    target_ids = set()
    sym_l = symbol.lower()
    for rec in recs:
        nm = str(rec.get("name", "")).lower()
        if nm == sym_l:
            cid = rec.get("id")
            if cid is not None:
                target_ids.add(str(cid))
    if not target_ids:
        return []
    rows_by_cid = {}
    for view in ["intent", "impl"]:
        vw = (indices.get("views") or {}).get(view) or {}
        for r in (vw.get("rows") or []):
            rows_by_cid.setdefault(str(r.get("chunk_id")), []).append((view, r))
    hits: List[Dict[str, Any]] = []
    for cid in target_ids:
        for view_r in rows_by_cid.get(cid, []):
            view, _row = view_r
            hits.append({"chunk_id": cid, "score": 3.0, "view": view})
    return hits

def _sanitize_citations(citations, allowed_ids):
    out = []
    if not isinstance(citations, (list, tuple)):
        return out
    for c in citations:
        if isinstance(c, dict) and "chunk_id" in c and c["chunk_id"] in allowed_ids:
            out.append({"chunk_id": c["chunk_id"]})
        elif isinstance(c, str) and c in allowed_ids:
            out.append({"chunk_id": c})
    seen = set(); dedup = []
    for c in out:
        if c["chunk_id"] not in seen:
            seen.add(c["chunk_id"]); dedup.append(c)
    return dedup

def answer_with_llm(
    index_dir: str,
    records_path: str,
    question: str,
    provider: LLMProvider,
    *,
    top_k: int = 20,
    hits: Optional[List[Dict[str, Any]]] = None
) -> Dict[str, Any]:
    """
    Retrieve context from indices/graph and ask the LLM to synthesize a grounded answer.

    Smart routing:
      - For callers/callees queries → answer deterministically from the graph.
      - For symbol explanation/location → build SOURCES and ask LLM.
      - For repo overview/change plan → use LLM with README + SOURCES.
      - Otherwise → fallback to LLM with SOURCES.

    Returns
    -------
    dict
        {
          "answer_md": str,
          "citations": list,
          "suggested_changes": list,
          "confidence": float,
          "debug": { ... }
        }
    """
    indices = load_indices(index_dir)
    _ = load_jsonl(records_path) if records_path else None
    cmap = _chunk_map(indices)

    # Detect intent
    mode = detect_intent(question)

    # Target symbol
    symbols = _symbol_tokens(question)
    target = None
    for t in symbols:
        if _find_symbol_rows(indices, t):
            target = t
            break
    if target is None and symbols:
        target = symbols[0]

    # Load graph if needed
    graph_path = Path(index_dir).parent / "graph.json"
    G = None
    if graph_path.exists():
        try:
            with open(graph_path, "r", encoding="utf-8") as f:
                data = json.load(f)
            G = json_graph.node_link_graph(data)
        except Exception:
            G = None

    # --- Graph-based answering for callers/callees ---
    if mode in {"callers_list", "callees_list"} and target and G is not None:
        results = []
        try:
            target_nodes = [cid for cid, _row, _ in _find_symbol_rows(indices, target)]
            for node in target_nodes:
                if node not in G:
                    continue
                if mode == "callers_list":
                    neighbors = list(G.predecessors(node))
                    header = f"Functions that call `{target}`"
                else:
                    neighbors = list(G.successors(node))
                    header = f"Functions called by `{target}`"

                for nbr in neighbors:
                    if "::" in str(nbr):
                        results.append({"chunk_id": str(nbr), "score": 1.0})
        except Exception:
            results = []

        if results:
            sources = _as_sources_with_meta(results, cmap, max_chunks=40, max_chars=900)
            return {
                "answer_md": header + ":\n\n" + "\n".join(
                    f"- {s['symbol']} ({s['path']})" for s in sources
                ),
                "citations": [{"chunk_id": s["chunk_id"]} for s in sources],
                "suggested_changes": [],
                "confidence": 0.9,
                "debug": {"mode": mode, "target_symbol": target, "graph_used": True, "sources": sources},
            }

    # --- Build/augment hits ---
    forced_hits: List[Dict[str, Any]] = []
    if target:
        for cid, _row, view in _find_symbol_rows(indices, target):
            forced_hits.append({"chunk_id": cid, "score": 2.0, "view": view})
        rec_hits = _hits_from_records(indices, records_path, target)
        seen = {str(h["chunk_id"]) for h in forced_hits}
        for h in rec_hits:
            if str(h["chunk_id"]) not in seen:
                forced_hits.append(h); seen.add(str(h["chunk_id"]))

    base_hits: List[Dict[str, Any]] = []
    if hits:
        base_hits = hits
    else:
        if not forced_hits:
            for name in ["intent", "impl"]:
                vw = (indices.get("views") or {}).get(name) or {}
                for r in (vw.get("rows") or [])[:top_k]:
                    base_hits.append({"chunk_id": r.get("chunk_id"), "score": 1.0, "view": name})

    seen = set()
    merged_hits: List[Dict[str, Any]] = []
    for h in forced_hits + base_hits:
        cid = str(h.get("chunk_id"))
        if cid not in seen:
            seen.add(cid); merged_hits.append(h)

    if not merged_hits:
        return {
            "answer_md": (
                "I couldn't locate matching symbols or chunks for this question in the current index. "
                "Re-index the repo and try again, or provide the file containing the target function/class."
            ),
            "citations": [],
            "suggested_changes": [],
            "confidence": 0.2,
            "debug": {"mode": mode, "target_symbol": target, "sources": [], "hits": []},
        }

    # --- SOURCES for LLM ---
    max_chars = 1400 if mode == "symbol_explain" else 900
    sources = _as_sources_with_meta(
        merged_hits,
        cmap,
        max_chunks=40 if mode == "symbol_explain" else 24,
        max_chars=max_chars
    )

    # Require target coverage
    if target:
        covers = [s for s in sources if (s.get("symbol") or "").lower() == target.lower() or f"::{target}" in s.get("chunk_id", "")]
        if not covers:
            return {
                "answer_md": (
                    f"I couldn't find the symbol `{target}` in the indexed chunks. "
                    "Please re-index or verify the symbol name/file."
                ),
                "citations": [],
                "suggested_changes": [],
                "confidence": 0.2,
                "debug": {"mode": mode, "target_symbol": target, "sources": sources, "hits": merged_hits},
            }

    root = _guess_root(indices)
    readme = _read_readme(root)

    def fmt_source(s: Dict[str, Any]) -> str:
        return f"- {s['chunk_id']} :: {s['path']} :: {s['kind']} :: {s['symbol']}\n  {s['text']}"

    context = "QUESTION:\n" + (question or "").strip() + "\n\n"
    if mode == "symbol_explain":
        context += (
            "TASK: Explain the function/class in detail. Cover: purpose, parameters & types (if visible), "
            "return value, side-effects, key branches/logic, dependencies (internal calls), and typical usage. "
            "Ground every claim with a citation.\n\n"
        )
    if readme and mode not in {"symbol_explain"}:
        lead_lines = [ln for ln in readme.splitlines() if ln.strip()][:12]
        context += "README (lead):\n" + "\n".join(lead_lines) + "\n\n"
    if target:
        context += f"TARGET_SYMBOL: {target}\n\n"
    context += "SOURCES:\n" + "\n".join(fmt_source(s) for s in sources)

    messages = [
        {"role": "system", "content": SYSTEM},
        {"role": "user", "content": context},
    ]

    resp = provider.chat(messages, temperature=0.2)
    content = (resp.get("content") or "").strip()

    def extract_json(text: str) -> Dict[str, Any]:
        m = re.search(r"\{.*\}", text, flags=re.S)
        if not m:
            return {}
        try:
            return json.loads(m.group(0))
        except Exception:
            return {}

    parsed: Dict[str, Any] = extract_json(content)

    if not parsed or not isinstance(parsed, dict) or not parsed.get("answer_md"):
        messages.append({"role": "assistant", "content": content})
        messages.append({"role": "user", "content": "Reformat to strict JSON only. "
                                                   "Ensure non-empty 'answer_md' grounded in SOURCES with citations. "
                                                   "Keep the same content; do not add external knowledge."})
        resp2 = provider.chat(messages, temperature=0)
        parsed = extract_json((resp2.get("content") or "")) or {"answer_md": content, "citations": []}

    ans = parsed.get("answer_md")
    if isinstance(ans, dict):
        parsed["answer_md"] = ans.get("content") or ans.get("text") or ans.get("markdown") or ans.get("md") or json.dumps(ans, ensure_ascii=False)
    elif isinstance(ans, list):
        parsed["answer_md"] = "\n".join(str(x) for x in ans)
    elif ans is None:
        parsed["answer_md"] = ""

    if not parsed["answer_md"].strip():
        parsed["answer_md"] = (
            "The provided SOURCES did not contain enough content to explain this symbol without guessing. "
            "Please re-index or narrow the question to a specific file or snippet."
        )
        parsed.setdefault("citations", [])
        parsed.setdefault("suggested_changes", [])
        parsed["confidence"] = 0.2

    allowed_ids = [s['chunk_id'] for s in sources]
    parsed["citations"] = _sanitize_citations(parsed.get("citations", []), allowed_ids)
    parsed.setdefault("suggested_changes", [])
    if "confidence" not in parsed or not isinstance(parsed["confidence"], (int, float)):
        parsed["confidence"] = 0.6 if parsed["citations"] else 0.4

    parsed["debug"] = {
        "mode": mode,
        "target_symbol": target,
        "sources": sources,
        "hits": merged_hits,
        "readme_included": bool(readme),
    }

    return parsed

def extract_json(text: str) -> Dict[str, Any]:
        m = re.search(r"\{.*\}", text, flags=re.S)
        if not m:
            return {}
        try:
            return json.loads(m.group(0))
        except Exception:
            return {}

def generate_code_plan(
    index_dir: str,
    records_path: str,
    task: str,
    provider: LLMProvider
) -> Dict[str, Any]:
    """Use LLM to propose a change plan and diffs (unified patch) grounded in SOURCES."""
    indices = load_indices(index_dir)
    _ = load_jsonl(records_path) if records_path else None

    cmap = _chunk_map(indices)
    # Use top impl-view rows for code-centric tasks
    impl_rows = (indices.get("views") or {}).get("impl", {}) or {}
    hits = [
        {"chunk_id": r.get("chunk_id"), "score": 1.0, "view": "impl"}
        for r in (impl_rows.get("rows") or [])[:24]
    ]
    sources = _as_sources_with_meta(hits, cmap, max_chunks=24, max_chars=700)

    SYSTEM2 = (
        "You are a principal engineer. Propose a step-by-step change plan and unified diffs "
        "to implement the requested change. Use ONLY provided SOURCES and cite with [[chunk_id]]. "
        "Return JSON with keys: plan_md, diffs (array of objects: file, patch), citations, confidence. "
        "Do not include prose outside JSON. "
    ) + ALLOWED_CITATION_NOTE

    def fmt_s(s: Dict[str, Any]) -> str:
        return f"- {s['chunk_id']} :: {s['path']} :: {s['kind']} :: {s['symbol']}\n  {s['text']}"

    context = "TASK:\n" + (task or "").strip() + "\n\nSOURCES:\n" + "\n".join(fmt_s(s) for s in sources)
    messages = [{"role": "system", "content": SYSTEM2}, {"role": "user", "content": context}]
    out_text = provider.chat(messages, temperature=0.2).get("content", "")
    try:
        m = re.search(r"\{.*\}", out_text, flags=re.S)
        parsed = json.loads(m.group(0)) if m else {"plan_md": out_text, "diffs": [], "citations": [], "confidence": 0.5}
    except Exception:
        parsed = {"plan_md": out_text, "diffs": [], "citations": [], "confidence": 0.5}

    allowed_ids = [s['chunk_id'] for s in sources]
    parsed["citations"] = _sanitize_citations(parsed.get("citations", []), allowed_ids)
    if "confidence" not in parsed or not isinstance(parsed["confidence"], (int, float)):
        parsed["confidence"] = 0.5

    parsed["debug"] = {"sources": sources, "hits": hits}
    return parsed

class LLMProvider:
    """Abstract base for LLM chat providers."""
    def chat(
        self,
        messages: List[Dict[str, str]],
        temperature: float = 0.2,
        max_tokens: Optional[int] = None,
        **kwargs: Any,
    ) -> Dict[str, Any]:
        raise NotImplementedError

def chat(
        self,
        messages: List[Dict[str, str]],
        temperature: float = 0.2,
        max_tokens: Optional[int] = None,
        **kwargs: Any,
    ) -> Dict[str, Any]:
        url = f"{self.base_url}/api/chat"
        # Ollama accepts options.*; we keep it minimal and override with caller extras.
        options = {"temperature": float(temperature)}
        options.update(self.extra_options)
        payload: Dict[str, Any] = {
            "model": self.model,
            "messages": messages,
            "stream": False,
            "options": options,
            # CRITICAL: force JSON output from the model tokenizer/sampler
            "format": "json",
        }
        if max_tokens is not None:
            # Ollama supports `num_predict` as a cap on tokens to generate
            options["num_predict"] = int(max_tokens)

        resp = requests.post(url, json=payload, timeout=self.timeout)
        try:
            resp.raise_for_status()
        except Exception as e:
            return {"content": "", "error": f"Ollama HTTP {resp.status_code}: {e}", "raw": getattr(resp, "text", "")}

        data = resp.json()
        # When `format=json`, Ollama returns the assistant content as a JSON string.
        content = ""
        if isinstance(data, dict):
            msg = data.get("message") or {}
            content = msg.get("content", "") or ""
            # Defensive: Sometimes models include stray text around JSON; return raw too.
        return {
            "content": content,
            "provider": "ollama",
            "model": self.model,
            "raw": data,
        }

class OpenAICompatProvider(LLMProvider):
    """
    Talks to an OpenAI-compatible /v1/chat/completions endpoint.

    We request JSON via response_format={'type': 'json_object'} when the server supports it.
    If the server rejects that field, we fall back to plain text and let the caller parse.
    """
    def __init__(
        self,
        model: str,
        base_url: str,
        api_key: Optional[str] = None,
        timeout: float = DEFAULT_TIMEOUT,
        headers: Optional[Dict[str, str]] = None,
    ) -> None:
        self.model = model
        self.base_url = base_url.rstrip("/")
        self.api_key = api_key or os.environ.get("OPENAI_API_KEY") or ""
        self.timeout = timeout
        self.headers = {"Content-Type": "application/json"}
        if self.api_key:
            self.headers["Authorization"] = f"Bearer {self.api_key}"
        if headers:
            self.headers.update(headers)

    def chat(
        self,
        messages: List[Dict[str, str]],
        temperature: float = 0.2,
        max_tokens: Optional[int] = None,
        **kwargs: Any,
    ) -> Dict[str, Any]:
        url = f"{self.base_url}/v1/chat/completions"
        body: Dict[str, Any] = {
            "model": self.model,
            "messages": messages,
            "temperature": float(temperature),
            "stream": False,
        }
        if max_tokens is not None:
            body["max_tokens"] = int(max_tokens)

        # Prefer strict JSON responses if supported
        try:
            body["response_format"] = {"type": "json_object"}
            resp = requests.post(url, json=body, headers=self.headers, timeout=self.timeout)
            # Some servers return 400 for unknown field; if so, retry without it.
            if resp.status_code >= 400:
                raise RuntimeError(f"HTTP {resp.status_code}")
        except Exception:
            body.pop("response_format", None)
            resp = requests.post(url, json=body, headers=self.headers, timeout=self.timeout)

        try:
            resp.raise_for_status()
        except Exception as e:
            return {"content": "", "error": f"OpenAICompat HTTP {resp.status_code}: {e}", "raw": getattr(resp, "text", "")}

        data = resp.json()
        content = ""
        try:
            content = (data.get("choices") or [{}])[0].get("message", {}).get("content", "") or ""
        except Exception:
            content = ""

        return {
            "content": content,
            "provider": "openai-compat",
            "model": self.model,
            "raw": data,
        }

